// NewUpsertKeyPayload builds a modelKeys service upsertKey endpoint payload.
func NewUpsertKeyPayload(body *UpsertKeyRequestBody, sessionToken *string, apikeyToken *string, projectSlugInput *string) *modelkeys.UpsertKeyPayload {
	v := &modelkeys.UpsertKeyPayload{
		Slot:     *body.Slot,
		Provider: *body.Provider,
		APIKey:   *body.APIKey,
	}
	if body.Enabled != nil {
		v.Enabled = *body.Enabled
	}
	if body.Enabled == nil {
		v.Enabled = true
	}
	v.SessionToken = sessionToken
	v.ApikeyToken = apikeyToken
	v.ProjectSlugInput = projectSlugInput

	return v
}

// NewDeleteKeyPayload builds a modelKeys service deleteKey endpoint payload.
func NewDeleteKeyPayload(id string, sessionToken *string, apikeyToken *string, projectSlugInput *string) *modelkeys.DeleteKeyPayload {
	v := &modelkeys.DeleteKeyPayload{}
	v.ID = id
	v.SessionToken = sessionToken
	v.ApikeyToken = apikeyToken
	v.ProjectSlugInput = projectSlugInput

	return v
}

// ValidateUpsertKeyRequestBody runs the validations defined on
// UpsertKeyRequestBody
func ValidateUpsertKeyRequestBody(body *UpsertKeyRequestBody) (err error) {
	if body.Slot == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("slot", "body"))
	}
	if body.Provider == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("provider", "body"))
	}
	if body.APIKey == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("api_key", "body"))
	}
	return
}
